const crypto = require('crypto');
const https = require('https');

const connectionString = $env.AZURE_STORAGE_CONNECTION_STRING || $env.AZURE_BLOB_CONNECTION_STRING;
let accountName, accountKey;
if (connectionString) {
  accountName = connectionString.match(/AccountName=([^;]+)/)?.[1];
  accountKey  = connectionString.match(/AccountKey=([^;]+)/)?.[1];
}
if (!accountName) accountName = $env.AZURE_STORAGE_ACCOUNT_NAME || 'stcompdldevqc01';
if (!accountKey)  accountKey  = $env.AZURE_STORAGE_ACCOUNT_KEY;

if (!accountKey) {
  throw new Error('Azure credentials not found. Set AZURE_STORAGE_CONNECTION_STRING in the n8n container environment.');
}

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      const chunks = [];
      res.on('data', chunk => chunks.push(chunk));
      res.on('end', () => resolve({ buffer: Buffer.concat(chunks), statusCode: res.statusCode, contentType: res.headers['content-type'] || 'application/octet-stream' }));
      res.on('error', reject);
    }).on('error', reject);
  });
}

function generateSasUrl(container, blobPath) {
  const now = new Date();
  const expiry = new Date(now.getTime() + 3600000);
  const sv = '2020-12-06';
  const fmt = (d) => d.toISOString().replace(/\.\d{3}Z$/, 'Z');
  const st = fmt(now);
  const se = fmt(expiry);
  const canonicalizedResource = `/blob/${accountName}/${container}/${blobPath}`;
  const stringToSign = ['r', st, se, canonicalizedResource, '', '', 'https', sv, 'b', '', '', '', '', '', '', ''].join('\n');
  const key = Buffer.from(accountKey, 'base64');
  const sig = crypto.createHmac('sha256', key).update(Buffer.from(stringToSign, 'utf8')).digest('base64');
  const qs = 'sv=' + encodeURIComponent(sv) + '&sr=b&sp=r&st=' + encodeURIComponent(st) + '&se=' + encodeURIComponent(se) + '&spr=https&sig=' + encodeURIComponent(sig);
  return `https://${accountName}.blob.core.windows.net/${container}/${blobPath}?${qs}`;
}

async function fetchBlob(container, blobPath) {
  const sasUrl = generateSasUrl(container, blobPath);
  const { buffer, statusCode, contentType } = await httpsGet(sasUrl);
  if (statusCode !== 200) {
    throw new Error(`Azure Blob download failed HTTP ${statusCode} for ${container}/${blobPath}. Body: ${buffer.toString().substring(0, 300)}`);
  }
  return { buffer, contentType };
}

const items = $input.all();
const result = [];

for (const item of items) {
  if (item.binary && Object.keys(item.binary).length > 0) {
    result.push(item);
    continue;
  }
  const bodyData = item.json.body || item.json;
  const blobPath = bodyData.blobPath;
  const blobFiles = bodyData.blobFiles;
  if (!blobPath && !blobFiles) {
    result.push(item);
    continue;
  }
  if (!item.binary) item.binary = {};
  if (blobPath) {
    const container = bodyData.azureContainer || 'complianceblobdev';
    const { buffer, contentType } = await fetchBlob(container, blobPath);
    const fileName = blobPath.split('/').pop();
    item.binary.data = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    item.json.azureBlobFetched = true;
    item.json.originalFileName = fileName;
  }
  if (blobFiles) {
    for (const [fieldName, blobInfo] of Object.entries(blobFiles)) {
      const bp = typeof blobInfo === 'string' ? blobInfo : blobInfo.blobPath;
      const container = (typeof blobInfo === 'object' && blobInfo.container) ? blobInfo.container : (item.json.azureContainer || 'complianceblobdev');
      const { buffer, contentType } = await fetchBlob(container, bp);
      const fileName = bp.split('/').pop();
      item.binary[fieldName] = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    }
    item.json.azureBlobFetched = true;
  }
  result.push(item);
}

return result;

const crypto = require('crypto');
const items = $input.all();
const firstItem = items[0];

let questionsRaw = firstItem.json?.questions || firstItem.json?.body?.questions || firstItem.json?.query?.questions;

console.log('First item keys:', Object.keys(firstItem.json || {}));
if (firstItem.binary) {
  console.log('Binary field keys:', Object.keys(firstItem.binary));
}

if (!questionsRaw) {
  throw new Error('Missing "questions" parameter. Expected JSON array: [{"question_id":"q1","files":["file1.pdf"]}]. Received structure: ' + JSON.stringify(Object.keys(firstItem.json || {})));
}

let questions;
try {
  if (typeof questionsRaw === 'string') {
    questionsRaw = questionsRaw.replace(/[\x00-\x1F\x7F]/g, ' ').trim();
  }
  questions = typeof questionsRaw === 'string' ? JSON.parse(questionsRaw) : questionsRaw;
} catch (e) {
  throw new Error('Invalid questions JSON format: ' + e.message);
}

if (!questions || !Array.isArray(questions) || questions.length === 0) {
  throw new Error('Questions must be non-empty array. Got: ' + typeof questions);
}

const domain = firstItem.json?.domain || firstItem.json?.body?.domain || firstItem.json?.query?.domain || 'General';

let totalSize = 0;
const fileMetadata = [];

if (firstItem.binary) {
  for (const [fieldName, binaryData] of Object.entries(firstItem.binary)) {
    if (!binaryData) continue;
    let fileSize;
    if (binaryData.fileSize != null) {
      fileSize = binaryData.fileSize;
    } else {
      const buf = await this.helpers.getBinaryDataBuffer(0, fieldName);
      fileSize = buf.length;
    }
    totalSize += fileSize;
    fileMetadata.push({ fieldName, fileName: binaryData.fileName || fieldName, fileSize, mimeType: binaryData.mimeType || 'application/octet-stream' });
  }
}

console.log('Binary fields available:', JSON.stringify(fileMetadata.map(f => ({ fieldName: f.fieldName, fileName: f.fileName }))));

if (totalSize > 500 * 1024 * 1024) {
  throw new Error(`Total file size exceeds 500MB limit (current: ${Math.round(totalSize/1024/1024)}MB)`);
}

function findUploadedFile(name) {
  const norm = (s) => s.replace(/[_ ]/g, ' ').trim().toLowerCase();
  return fileMetadata.find(f => f.fieldName === name || f.fileName === name || norm(f.fieldName) === norm(name) || norm(f.fileName) === norm(name));
}

for (const q of questions) {
  if (!q.question_id) throw new Error('Each question must have a "question_id" field');
  if (!q.files || !Array.isArray(q.files) || q.files.length === 0) throw new Error(`Question ${q.question_id} has no files specified`);
  q.files = q.files.map(fileName => {
    const found = findUploadedFile(fileName);
    if (!found) {
      const available = fileMetadata.map(f => f.fieldName + ' (file: ' + f.fileName + ')').join(', ');
      throw new Error(`Question ${q.question_id} references file "${fileName}" which was not uploaded. Available: [${available}]`);
    }
    return found.fieldName;
  });
}

firstItem.json = { questions, domain, files: fileMetadata, totalSizeMB: Math.round(totalSize / 1024 / 1024 * 100) / 100, totalFiles: fileMetadata.length };

return [firstItem];

