const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const sessionData = $('Create Audit Session').first().json;
const sessionId = sessionData.session_id;
const domain = sessionData.domain_id;

const inputData = $input.first();
const questions = inputData.json.questions;
const binaryData = inputData.binary;

if (!binaryData || Object.keys(binaryData).length === 0) {
  throw new Error('No binary data found in input');
}

const binaryKeys = Object.keys(binaryData);
const sessionDir = `/tmp/n8n_processing/${sessionId}`;
if (!fs.existsSync(sessionDir)) {
  fs.mkdirSync(sessionDir, { recursive: true });
}

console.log(`Created session directory: ${sessionDir}`);

const items = [];

for (let ki = 0; ki < binaryKeys.length; ki++) {
  const fieldName = binaryKeys[ki];
  const fileData = binaryData[fieldName];
  if (!fileData) continue;
  const buffer = await this.helpers.getBinaryDataBuffer(0, fieldName);
  const hash = crypto.createHash('sha256').update(buffer).digest('hex');
  const ext = path.extname(fileData.fileName) || '.bin';
  const diskFileName = `${hash}${ext}`;
  const filePath = path.join(sessionDir, diskFileName);
  items.push({
    json: { sessionId, domain, fieldName, fileName: fileData.fileName, originalFileName: fileData.fileName, mimeType: fileData.mimeType, fileSize: buffer.length, hash, filePath, questions },
    binary: { data: fileData }
  });
}

if (items.length === 0) throw new Error('No files processed');

return items;

const items = $input.all();
const firstItem = items[0].json;
const sessionId = firstItem.sessionId;
const domain = firstItem.domain;
const questions = firstItem.questions;

const fileMap = {};
for (const item of items) {
  const row = item.json;
  const originalName = row.originalFileName || row.fileName;
  fileMap[row.fieldName] = { hash: row.hash, fileName: originalName, fileSize: row.fileSize, mimeType: row.mimeType, fieldName: row.fieldName, filePath: row.filePath };
}

const questionsWithHashes = questions.map(q => ({
  question_id: q.question_id,
  evidence_files: q.files.map(fileName => {
    const fileInfo = fileMap[fileName];
    return { hash: fileInfo.hash, originalName: fileInfo.fileName, fieldName: fileName };
  })
}));

return [{ json: { sessionId, domain, questions: questionsWithHashes, fileMap, totalFiles: Object.keys(fileMap).length } }];

const crypto = require('crypto');
const data = $('Aggregate Files').first().json;

console.log('Build Redis Job - received data keys:', Object.keys(data));

if (!data.questions || !Array.isArray(data.questions)) {
  throw new Error('Invalid data received: questions is ' + typeof data.questions + '. Full data keys: ' + Object.keys(data).join(', '));
}

const jobId = crypto.randomUUID();
const job = { jobId, sessionId: data.sessionId, domain: data.domain, questions: data.questions, fileMap: data.fileMap, sessionDir: `/tmp/n8n_processing/${data.sessionId}`, status: 'queued', createdAt: new Date().toISOString() };

return [{ json: { jobData: JSON.stringify(job), jobId, sessionId: data.sessionId, totalQuestions: data.questions.length } }];

